import React from 'react';
import { useNavigate } from 'react-router-dom';

function Home() {
  const navigate = useNavigate();

  return (
    <div>
      <h1>HOME OK</h1>

      <button onClick={() => navigate('/cadastro')}>
        Ir para Cadastro
      </button>
    </div>
  );
}

export default Home;
